function useNotif(){
  const [n,setN]=useState(null);
  const show=(msg,type="success")=>{setN({msg,type});setTimeout(()=>setN(null),3500);};
  const Notif=()=>n?React.createElement("div",{style:{position:"fixed",top:16,right:16,background:n.type==="error"?`${C.red}1a`:n.type==="warn"?`${C.amber}1a`:`${C.green}1a`,border:`1px solid ${n.type==="error"?C.red:n.type==="warn"?C.amber:C.green}`,color:C.text,borderRadius:10,padding:"10px 16px",fontSize:12,fontWeight:600,zIndex:2000,boxShadow:"0 4px 20px #0006",animation:"slideIn .22s ease",maxWidth:320}},n.msg):null;
  return {show,Notif};
}

